import { describe, it, expect, vi, beforeEach } from "vitest";
import {
  inferBmmPhase,
  buildNextSteps,
  buildWorkflowList,
  getSprintStatus,
} from "../bmadState.js";

//  Added buildWorkflowList suite (non-bmm filter, anytime filter,required→boolean).
// Added getSprintStatus epic grouping suite with vi.mock for fs and loadYaml.

vi.mock("fs", async (importOriginal) => {
  const actual = await importOriginal();
  return {
    ...actual,
    default: {
      ...actual.default,
      existsSync: vi.fn(actual.default.existsSync),
    },
  };
});
vi.mock("../fileUtils.js", async (importOriginal) => {
  const actual = await importOriginal();
  return { ...actual, loadYaml: vi.fn() };
});

describe("inferBmmPhase", () => {
  const workflows = [
    {
      module: "bmm",
      phase: "1-analysis",
      sequence: "10",
      code: "cp",
      required: "true",
    },
    {
      module: "bmm",
      phase: "2-planning",
      sequence: "20",
      code: "ca",
      required: "true",
    },
    {
      module: "bmm",
      phase: "3-solutioning",
      sequence: "30",
      code: "ce",
      required: "true",
    },
    {
      module: "bmm",
      phase: "4-implementation",
      sequence: "10",
      code: "sp",
      required: "true",
    },
  ];

  it("returns 1-analysis when no artifacts exist", () => {
    const artifacts = {
      hasPrd: false,
      hasArchitecture: false,
      hasEpics: false,
      hasUx: false,
      hasSprintStatus: false,
    };
    expect(inferBmmPhase(artifacts, workflows).phase).toBe("1-analysis");
  });

  it("returns 2-planning when only PRD exists", () => {
    const artifacts = {
      hasPrd: true,
      hasArchitecture: false,
      hasEpics: false,
      hasUx: false,
      hasSprintStatus: false,
    };
    expect(inferBmmPhase(artifacts, workflows).phase).toBe("2-planning");
  });

  it("returns 3-solutioning when PRD and Architecture exist", () => {
    const artifacts = {
      hasPrd: true,
      hasArchitecture: true,
      hasEpics: false,
      hasUx: false,
      hasSprintStatus: false,
    };
    expect(inferBmmPhase(artifacts, workflows).phase).toBe("3-solutioning");
  });

  it("returns 4-implementation when sprint status exists", () => {
    const artifacts = {
      hasPrd: true,
      hasArchitecture: true,
      hasEpics: true,
      hasUx: false,
      hasSprintStatus: true,
    };
    expect(inferBmmPhase(artifacts, workflows).phase).toBe("4-implementation");
  });

  it("stays in 1-analysis with no artifacts even when implementation workflow (ir) exists", () => {
    const workflowsWithIr = [
      ...workflows,
      {
        module: "bmm",
        phase: "4-implementation",
        sequence: "10",
        code: "ir",
        required: "true",
      },
    ];
    const artifacts = {
      hasPrd: false,
      hasArchitecture: false,
      hasEpics: false,
      hasUx: false,
      hasSprintStatus: false,
    };
    expect(inferBmmPhase(artifacts, workflowsWithIr).phase).toBe("1-analysis");
  });
});

describe("buildWorkflowList", () => {
  const workflows = [
    {
      module: "bmm",
      phase: "1-analysis",
      sequence: "10",
      name: "Analyse",
      code: "ca",
      command: "bmm_analyse",
      required: "true",
      "agent-display-name": "Analyst",
      description: "Do analysis",
    },
    {
      module: "other",
      phase: "1-analysis",
      sequence: "10",
      name: "Other",
      code: "ox",
      command: "other_cmd",
      required: "true",
      "agent-display-name": "Other",
      description: "Other",
    },
    {
      module: "bmm",
      phase: "anytime",
      sequence: "99",
      name: "Always",
      code: "ay",
      command: "bmm_always",
      required: "false",
      "agent-display-name": "Agent",
      description: "Anytime",
    },
    {
      module: "bmm",
      phase: "2-planning",
      sequence: "20",
      name: "Plan",
      code: "cp",
      command: "bmm_plan",
      required: "false",
      "agent-display-name": "PM",
      description: "Plan",
    },
  ];

  it("filters out non-bmm modules", () => {
    const result = buildWorkflowList(workflows);
    expect(result.every((w) => w.phase !== undefined)).toBe(true);
    // 'other' module entry must be excluded
    expect(result.find((w) => w.code === "ox")).toBeUndefined();
  });

  it("filters out anytime phase", () => {
    const result = buildWorkflowList(workflows);
    expect(result.find((w) => w.phase === "anytime")).toBeUndefined();
  });

  it("converts required to boolean", () => {
    const result = buildWorkflowList(workflows);
    expect(result.find((w) => w.code === "ca").required).toBe(true);
    expect(result.find((w) => w.code === "cp").required).toBe(false);
  });
});

describe("buildNextSteps", () => {
  const workflows = [
    {
      module: "bmm",
      phase: "1-analysis",
      sequence: "10",
      command: "bmm_create_prd",
      description: "Create PRD",
    },
    {
      module: "bmm",
      phase: "2-planning",
      sequence: "20",
      command: "bmm_create_architecture",
      description: "Create Arch",
    },
  ];
  const phaseInfo = { phase: "1-analysis", nextSequence: 10 };
  const artifacts = {};

  it("includes steps from current and later phases", () => {
    const steps = buildNextSteps(workflows, phaseInfo, artifacts);
    expect(steps.length).toBeGreaterThan(0);
    expect(steps[0]).toHaveProperty("commandDisplay");
    expect(steps[0].commandDisplay).toMatch(/^\/bmad-/);
  });

  it("returns at most 6 steps", () => {
    const many = Array.from({ length: 20 }, (_, i) => ({
      module: "bmm",
      phase: "1-analysis",
      sequence: String(i),
      command: `cmd_${i}`,
    }));
    const steps = buildNextSteps(
      many,
      { phase: "1-analysis", nextSequence: null },
      artifacts,
    );
    expect(steps.length).toBeLessThanOrEqual(6);
  });
});

describe("getSprintStatus epic grouping", () => {
  let fsMod;
  let fileUtilsMod;

  beforeEach(async () => {
    fsMod = await import("fs");
    fileUtilsMod = await import("../fileUtils.js");
    vi.resetAllMocks();
  });

  it("groups stories under epics", async () => {
    fsMod.default.existsSync.mockReturnValue(true);
    fileUtilsMod.loadYaml.mockResolvedValue({
      project: "test",
      generated: "2024-01-01",
      development_status: {
        "epic-1": "in-progress",
        "epic-1-story-1": "done",
        "epic-1-story-2": "in-progress",
        "epic-2": "backlog",
        "epic-2-story-1": "backlog",
      },
    });
    const result = await getSprintStatus("/fake/path");
    expect(result.epics).toHaveLength(2);
    expect(result.epics[0].id).toBe("epic-1");
    expect(result.epics[0].stories).toHaveLength(2);
    expect(result.epics[1].id).toBe("epic-2");
    expect(result.stories).toHaveLength(0);
  });

  it("returns null when sprint-status.yaml does not exist", async () => {
    fsMod.default.existsSync.mockReturnValue(false);
    const result = await getSprintStatus("/fake/path");
    expect(result).toBeNull();
  });
});
